}

func int_to_base(num: Int64, base: Int64): String {
    if num == 0 {
        return "0"
    }

    digits := "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    var result: String

    is_negative := num < 0
    if is_negative {
        num = -num
    }

    for num > 0 {
        remainder := num % base
        num = num / base
        result = strings.concat(strings.char_at(digits, remainder), result)
    }

    if is_negative {
        result = strings.concat("-", result)
    }

    return result
}
