    base36_digits := "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    base36_str := ""

    if n3 == 0 {
        base36_str = "0"
    } else {
        num := n3
        while num > 0 {
            remainder := num % 36
            base36_str = string(base36_digits[remainder]) + base36_str
            num = num / 36
        }
    }

    return hex_str + base36_str
}
